import org.verapdf.wcag.algorithms.semanticalgorithms.containers.StaticContainers;

public class FooterRepro {
    private static TextLine line(int page, double bottom, double top, String text) {
        return new TextLine(new TextChunk(new BoundingBox(page, 50.0, bottom, 250.0, top), text, 9.0, bottom));
    }
    private static void addPage(List<List<IObject>> contents, int page, String footerText, boolean withNote) {
        List<IObject> pageContents = new ArrayList<>();
        pageContents.add(line(page, 700, 712, "Body title " + page));
        pageContents.add(line(page, 300, 312, "Normal body " + page));
        if (withNote) {
            pageContents.add(line(page, 116, 125, "※ 출수 중 출수 버튼을 터치하면 출수가 정지됩니다."));
        }
        pageContents.add(line(page, 43, 52, footerText));
        contents.add(pageContents);
    }
    public static void main(String[] args) {
        StaticContainers.setIsDataLoader(true);
        StaticContainers.setIsIgnoreCharactersWithoutUnicode(false);
        StaticResources.setDocument(null);
        StaticLayoutContainers.setCurrentContentId(0);
        List<List<IObject>> contents = new ArrayList<>();
        addPage(contents, 0, "18 CERAGEM BALANCE USER MANUAL", false);
        addPage(contents, 1, "19 CERAGEM BALANCE USER MANUAL", true);
        addPage(contents, 2, "20 CERAGEM BALANCE USER MANUAL", true);
        addPage(contents, 3, "21 CERAGEM BALANCE USER MANUAL", false);
        HeaderFooterProcessor.processHeadersAndFooters(contents, false);
        for (int i = 0; i < contents.size(); i++) {
            int footers = 0;
            boolean noteInBody = false;
            boolean noteInFooter = false;
            double footerHeight = -1;
            int footerChildren = 0;
            for (IObject obj : contents.get(i)) {
                String value = String.valueOf(obj);
                if (obj instanceof SemanticHeaderOrFooter && ((SemanticHeaderOrFooter)obj).getSemanticType() == SemanticType.FOOTER) {
                    footers++;
                    footerHeight = obj.getBoundingBox().getHeight();
                    footerChildren = ((SemanticHeaderOrFooter)obj).getContents().size();
                    for (IObject child : ((SemanticHeaderOrFooter)obj).getContents()) {
                        if (String.valueOf(child).contains("출수 중")) noteInFooter = true;
                    }
                } else if (value.contains("출수 중")) {
                    noteInBody = true;
                }
            }
            System.out.printf(Locale.ROOT, "page=%d footers=%d footerHeight=%.1f children=%d noteInBody=%s noteInFooter=%s size=%d%n", i+18, footers, footerHeight, footerChildren, noteInBody, noteInFooter, contents.get(i).size());
        }
    }
}
