        if (content instanceof INode) {
            INode node = (INode) content;
            if (node.getSemanticType() == SemanticType.HEADER || node.getSemanticType() == SemanticType.FOOTER) {
                return true;
            }
        }
        return false;
    }

    private static List<IObject> filterHeaderOrFooterContents(List<IObject> contents, int pageNumber, boolean isHeaderDetection) {
        BoundingBox boundingBox = DocumentProcessor.getPageBoundingBox(pageNumber);
        List<IObject> edgeContents = new ArrayList<>();
        for (IObject content : contents) {
            if (boundingBox != null) {
                if (isHeaderDetection) {
                    if (content.getBottomY() < boundingBox.getHeight() * 2 / 3) {
                        continue;
                    }
                } else {
                    if (content.getTopY() > boundingBox.getHeight() / 3) {
                        continue;
                    }
                }
            }
            edgeContents.add(content);
        }
        return filterEdgeConnectedContents(edgeContents, isHeaderDetection);
    }

    private static List<IObject> filterEdgeConnectedContents(List<IObject> contents, boolean isHeaderDetection) {
        if (contents.size() < 2) {
            return contents;
        }
        if (isHeaderDetection) {
            return filterHeaderConnectedContents(contents);
        }
        return filterFooterConnectedContents(contents);
    }

    private static List<IObject> filterHeaderConnectedContents(List<IObject> contents) {
        List<IObject> result = new ArrayList<>();
        IObject previous = null;
        for (IObject content : contents) {
            if (previous != null && areVerticallySeparated(previous, content, true)) {
                break;
            }
            result.add(content);
            previous = content;
        }
        return result;
    }

    private static List<IObject> filterFooterConnectedContents(List<IObject> contents) {
        LinkedList<IObject> result = new LinkedList<>();
        IObject previous = null;
        for (int index = contents.size() - 1; index >= 0; index--) {
            IObject content = contents.get(index);
            if (previous != null && areVerticallySeparated(previous, content, false)) {
                break;
            }
            result.addFirst(content);
            previous = content;
        }
        return result;
    }

    private static boolean areVerticallySeparated(IObject edgeContent, IObject nextContent, boolean isHeaderDetection) {
        double gap = isHeaderDetection ? edgeContent.getBottomY() - nextContent.getTopY()
                : nextContent.getBottomY() - edgeContent.getTopY();
        if (gap <= 0) {
            return false;
        }
        double maxHeight = Math.max(edgeContent.getHeight(), nextContent.getHeight());
        double maxAllowedGap = Math.max(MIN_EDGE_CLUSTER_GAP, maxHeight * MAX_EDGE_CLUSTER_GAP_TO_HEIGHT_RATIO);
        return gap > maxAllowedGap;
    }

    private static boolean arePossibleHeadersOrFooters(IObject object1, IObject object2, int increment) {
